arguments.command:
SYMDIR="/tmp/sv-896e7d5fa7aa4082be504d8fa4785385/symbols"
DBG="$SYMDIR/libmonosgen-2.0.so.dbg"

# Use objdump to find the closest function symbol for the SGen worker addresses
# First let's get the symbol table and find what function each address falls in
for addr in 0x2f4b20 0x2f4c84; do
  echo "=== $addr ==="
  # Find the closest symbol at or before this address
  llvm-objdump --syms "$DBG" 2>/dev/null | awk -v target="$addr" '
    BEGIN { targetval = strtonum(target); best = ""; bestaddr = 0 }
    /^[0-9a-f]+ / {
      val = strtonum("0x" $1)
      if (val <= targetval && val > bestaddr) {
        bestaddr = val
        best = $0
      }
    }
    END { print best }
  '
  echo ""
done

