arguments.command:
SYMDIR="/tmp/sv-896e7d5fa7aa4082be504d8fa4785385/symbols"
DBG="$SYMDIR/libmonosgen-2.0.so.dbg"

# Use dynamic symbol table and regular symbol table for function-level symbols
(llvm-objdump -T "$DBG" 2>/dev/null; llvm-nm --defined-only "$DBG" 2>/dev/null) | \
  grep -i ' [tTwW] ' | \
  awk -v t1="0x2f4b20" -v t2="0x2f4c84" '
    BEGIN { tv1 = strtonum(t1); tv2 = strtonum(t2) }
    {
      val = strtonum("0x" $1)
      if (val <= tv1 && val > best1v) { best1v = val; best1 = $0 }
      if (val <= tv2 && val > best2v) { best2v = val; best2 = $0 }
    }
    END {
      print "0x2f4b20 -> " best1 " (offset +" sprintf("0x%x", tv1 - best1v) ")"
      print "0x2f4c84 -> " best2 " (offset +" sprintf("0x%x", tv2 - best2v) ")"
    }
  '

